import React from 'react';

function Header() {
  const currentDate = new Date();
  const options = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
  const formattedDate = currentDate.toLocaleDateString('en-US', options);

  return (
    <header className="flex items-center justify-between px-6 py-4 bg-gradient-to-r from-purple-700 via-indigo-700 to-purple-900 shadow-lg">
    
      <div className="text-center flex-1">
        <h1 className="text-3xl font-bold text-white">MeetingBot</h1>
        <p className="text-gray-300 text-sm">AI-Powered Audio & Text File Transcription with Summarization</p>
        <p className="text-sm text-gray-300 mt-1">{formattedDate}</p> {/* ✅ Date here */}
      </div>
      
      <div className="w-10"></div>
    </header>
  );
}

export default Header;

